// 🔥 Configuração direta do Firebase (sem variáveis de ambiente)
import { initializeApp } from "firebase/app";
import {
  getAuth,
  onAuthStateChanged,
  createUserWithEmailAndPassword,
  signInWithEmailAndPassword,
  signOut,
} from "firebase/auth";
import {
  getFirestore,
  doc,
  getDoc,
  setDoc,
  collection,
  getDocs,
  query,
  where,
  deleteDoc,
} from "firebase/firestore";

// ✅ Inicializa primeiro o app e só depois exporta o resto
const firebaseConfig = {
  apiKey: "AIzaSyDezKzZ3K6I2t8PCeJQxA94E_7JdZJrlEM",
  authDomain: "votacao-condominio.firebaseapp.com",
  projectId: "votacao-condominio",
  storageBucket: "votacao-condominio.appspot.com",
  messagingSenderId: "1051388818506",
  appId: "1:1051388818506:web:c30ad2d8ab16aef23d6c32",
  measurementId: "G-64KQ39D90Y",
};

// 🚀 Inicializa o app ANTES de usar auth/db
const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getFirestore(app);

// 👇 Agora o onAuthStateChanged pode usar o auth normalmente
export const observarUsuario = (callback) => {
  return onAuthStateChanged(auth, (user) => {
    callback(user);
  });
};

// 🔹 Exportações extras
export {
  createUserWithEmailAndPassword,
  signInWithEmailAndPassword,
  signOut,
  doc,
  getDoc,
  setDoc,
  getDocs,
  collection,
  query,
  where,
  deleteDoc,
};
